        return a_set <= diffs

    def search(b, depth):
        if covered(b):
            return True
        if depth == 0:
            return False
        b_list = list(b)
        candidates = set()
        for x in b_list:
            for ai in a_set:
                candidates.add(x + ai)
                candidates.add(x - ai)
        # Remove already used values
        candidates -= b
        # Limit candidates to avoid explosion
        candidates = sorted(candidates)[:50]
        for c in candidates:
            if search(b | frozenset([c]), depth - 1):
                return True
        return False

